export type TrayActionInput = {
	/**
	 *  Closed-set action identifier. Rejected at deserialization if the
	 *  caller supplies an unknown value.
	 */
	kind: TrayActionKind,
};

/**
 *  Closed set of tray menu actions. Adding a new action means:
 *    1. Add a variant here.
 *    2. Handle it in the frontend `AppShell`'s `app:tray_action` switch.
 *    3. Wire the tray menu item to call `emit_tray_action({ kind })`.
 * 
 *  Serialized as snake_case over IPC so the JSON wire form is stable
 *  against Rust-side renames.
 */
export type TrayActionKind = "open_sightline" | "open_library" | "open_timeline" | "open_downloads" | "open_settings" | "pause_all" | "resume_all";

export type TriggerPollInput = {
	// If omitted, the poller re-evaluates every due streamer on its next tick.
	twitchUserId: string | null,
};

export type UpdateWatchProgressInput = {
	vodId: string,
	positionSeconds: number,
	durationSeconds: number,
};

/**
 *  Single-choke-point answer for `<video src>`. The player uses this
 *  to decide which state to render — the happy path (`ready`), the
 *  "file moved / deleted externally" path (`missing`), or the
 *  partial-download path (`partial`, download not finished yet).
 */
export type VideoSource = {
	vodId: string,
	/**
	 *  `None` when state != "ready". Always absolute and verified to
	 *  sit inside the library root.
	 */
	path: string | null,
	state: VideoSourceState,
};

export type VideoSourceState = "ready" | "missing" | "partial";

// Storage-aligned VOD row. The `*_at` fields are unix seconds UTC.
export type Vod = {
	twitchVideoId: string,
	twitchUserId: string,
	streamId: string | null,
	title: string,
	description: string,
	streamStartedAt: number,
	publishedAt: number,
	url: string,
	thumbnailUrl: string | null,
	durationSeconds: number,
	viewCount: number,
	language: string,
	mutedSegments: MutedSegment[],
	isSubOnly: boolean,
	helixGameId: string | null,
	helixGameName: string | null,
	ingestStatus: IngestStatus,
	statusReason: string,
	firstSeenAt: number,
	lastSeenAt: number,
};

/**
 *  Renderer-facing bundle of per-VOD asset paths. Every `path` is an
 *  absolute filesystem string; the frontend passes each through
 *  `convertFileSrc`.
 */
export type VodAssets = {
	vodId: string,
	/**
	 *  Path to the `.mp4` under the library root if the download has
	 *  completed; `None` otherwise.
	 */
	videoPath: string | null,
	// Single-frame thumbnail from the Phase-3 pipeline.
	thumbnailPath: string | null,
	/**
	 *  Ordered list of six hover-preview frames. Empty if the preview
	 *  set is missing (pre-Phase-5 download that hasn't been backfilled
	 *  yet, or an ffmpeg failure).
	 */
	previewFramePaths: string[],
};

export type VodAssetsInput = {
	vodId: string,
};

/**
 *  VOD list filter. Every field is optional; omitted keys mean
 *  "no constraint". `#[specta(optional)]` ensures the TS emission is
 *  `T?: T` rather than `T | null` required keys — see ADR-0009.
 */
export type VodFilters = {
	streamerIds?: string[] | null,
	// Mirrors `IngestStatus` db strings; caller may send any subset.
	statuses?: string[] | null,
	gameIds?: string[] | null,
	// Unix seconds UTC.
	since?: number | null,
	until?: number | null,
};

export type VodIdInput = {
	vodId: string,
};

export type VodIngestedEvent = {
	twitchVideoId: string,
	twitchUserId: string,
	// Mirrors `vods.ingest_status`.
	ingestStatus: string,
	streamStartedAt: number,
};

export type VodSort = "stream_started_at_desc" | "stream_started_at_asc";

export type VodUpdatedEvent = {
	twitchVideoId: string,
	ingestStatus: string,
};

export type VodWithChapters = {
	vod: Vod,
	chapters: Chapter[],
	// Streamer display name, denormalized for convenience.
	streamerDisplayName: string,
	streamerLogin: string,
};

export type WatchCompletedEvent = {
	vodId: string,
};

/**
 *  Public snapshot of a VOD's watch progress — serialised to the
 *  frontend via IPC and included in the Continue Watching row.
 */
export type WatchProgressRow = {
	vodId: string,
	positionSeconds: number,
	durationSeconds: number,
	watchedFraction: number,
	state: WatchState,
	firstWatchedAt: number | null,
	lastWatchedAt: number,
	lastSessionDurationSeconds: number,
	totalWatchSeconds: number,
};

export type WatchProgressUpdatedEvent = {
	vodId: string,
	positionSeconds: number,
	// Mirrors `WatchState` db strings.
	state: string,
};

/**
 *  Canonical watch state. Wire strings match the CHECK constraint in
 *  migration 0008.
 */
export type WatchState = "unwatched" | "in_progress" | "completed" | "manually_watched";

export type WatchStateChangedEvent = {
	vodId: string,
	from: string,
	to: string,
};

/**
 *  Aggregate stats used by the later "hours watched this streamer"
 *  summaries. Defined now so the command + binding types are stable.
 */
export type WatchStats = {
	totalWatchSeconds: number,
	completedCount: number,
	inProgressCount: number,
};

/**
 *  Distinct from `crate::commands::downloads::VodIdInput` (downloads)
 *  and `crate::commands::media::VodAssetsInput` so tauri-specta
 *  doesn't collide on the type-name when emitting the bindings. The
 *  wire shape is identical.
 */
export type WatchVodIdInput = {
	vodId: string,
};

/**
 *  What happens when the user clicks the window close button.
 * 
 *  - `Hide` (default, new Phase-4 behaviour): the window is hidden,
 *    poller + download queue keep running, tray stays on.
 *  - `Quit`: explicit quit. Tokio services drain gracefully and the
 *    process exits.
 */
export type WindowCloseBehavior = "hide" | "quit";

/* Tauri Specta runtime */
async function typedError<T, E>(result: Promise<T>): Promise<{ status: "ok"; data: T } | { status: "error"; error: E }> {
    try {
        return { status: "ok", data: await result };
    } catch (e) {
        if (e instanceof Error) throw e;
        return { status: "error", error: e as any };
    }
}

